# --- Caching Decorator ---

def cache(expire_seconds=REDIS_EXPIRE_SECONDS):
    """
    A decorator to cache function results in Redis.
    The cache key is generated from the function name and its arguments.
    """
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Generate a unique cache key based on function name and arguments
            # Simple serialization for args/kwargs. For complex objects, you might need a more robust approach.
            cache_key_parts = [func.__module__, func.__name__]
            cache_key_parts.extend(str(arg) for arg in args)
            cache_key_parts.extend(f"{k}={v}" for k, v in sorted(kwargs.items()))
            cache_key = ":".join(cache_key_parts)
            
            # Prefix for cache keys to distinguish from sessions
            full_cache_key = f"cache:{cache_key}"

            # Try to get data from cache
